={
  "model": "claude-sonnet-4-5",
  "max_tokens": 2048,
  "system": "You are an expert social media content strategist. Given a topic and brand voice, create platform-optimized content for LinkedIn, Twitter/X, and Instagram. Return ONLY a JSON object with keys: linkedin (string, professional post 150-300 words with hashtags), twitter (string, max 280 chars, punchy with 2-3 hashtags), instagram (string, engaging caption 100-150 words with 10-15 hashtags), hook (string, attention-grabbing opening line used across platforms).",
  "messages": [{
    "role": "user",
    "content": "Topic: {{ $json.body.topic }}\nBrand Voice: {{ $json.body.brand_voice || 'professional and helpful' }}\nTarget Audience: {{ $json.body.target_audience || 'business professionals' }}\nCall to Action: {{ $json.body.cta || 'Learn more' }}"
  }]
}

parameters.jsCode:
const response = $input.first().json;
const text = response.content[0].text;
try {
  const content = JSON.parse(text);
  return [{ json: { ...content, generated_at: new Date().toISOString(), model: response.model, tokens_used: response.usage.output_tokens } }];
} catch(e) {
  return [{ json: { linkedin: text, twitter: text.substring(0, 280), instagram: text, hook: text.split('.')[0], error: 'Could not parse structured response' } }];
}
